import base64
import json
import logging
from datetime import datetime

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Define allowed task types and their handlers explicitly
ALLOWED_TASK_TYPES = {}


def register_task(task_type):
    """Decorator to register allowed task handlers."""
    def decorator(func):
        ALLOWED_TASK_TYPES[task_type] = func
        return func
    return decorator


@register_task("data_transform")
def handle_data_transform(payload):
    """Example handler for data transformation tasks."""
    input_data = payload.get("data", [])
    operation = payload.get("operation", "identity")

    if operation == "sum":
        return {"result": sum(input_data)}
    elif operation == "count":
        return {"result": len(input_data)}
    elif operation == "average":
        return {"result": sum(input_data) / len(input_data) if input_data else 0}
    else:
        raise ValueError(f"Unknown operation: {operation}")


@register_task("batch_process")
def handle_batch_process(payload):
    """Example handler for batch processing tasks."""
    items = payload.get("items", [])
    results = []
    for item in items:
        # Process each item in the batch
        results.append({"item_id": item.get("id"), "status": "processed"})
    return {"processed_count": len(results), "results": results}


@register_task("aggregation")
def handle_aggregation(payload):
    """Example handler for aggregation tasks."""
    datasets = payload.get("datasets", [])
    aggregated = {}
    for dataset in datasets:
        for key, value in dataset.items():
            if key in aggregated:
                aggregated[key] += value
            else:
                aggregated[key] = value
    return {"aggregated": aggregated}


def validate_message(message_data):
    """Validate and parse message data safely using JSON."""
    if not isinstance(message_data, (str, bytes)):
        raise ValueError("Invalid message data type")

    if isinstance(message_data, bytes):
        message_data = message_data.decode("utf-8")

    parsed = json.loads(message_data)

    # Validate required fields
    if not isinstance(parsed, dict):
        raise ValueError("Message must be a JSON object")

    if "task_type" not in parsed:
        raise ValueError("Message must contain 'task_type'")

    if "payload" not in parsed:
        raise ValueError("Message must contain 'payload'")

    task_type = parsed["task_type"]
    if task_type not in ALLOWED_TASK_TYPES:
        raise ValueError(
            f"Unknown task type: {task_type}. "
            f"Allowed types: {list(ALLOWED_TASK_TYPES.keys())}"
        )

    return parsed


def process_pubsub_message(event, context):
    """
    Cloud Function entry point for processing Pub/Sub messages.

    Uses JSON serialization instead of pickle to safely deserialize
    complex data structures without risk of arbitrary code execution.

    Expected message format (JSON):
    {
        "task_type": "data_transform",
        "payload": { ... },
        "metadata": { "job_id": "...", "priority": 1 }
    }
    """
    logger.info(
        "Processing message_id=%s, published at %s",
        context.event_id,
        context.timestamp,
    )

    try:
        # Decode the Pub/Sub message
        raw_data = base64.b64decode(event["data"])

        # Safely parse and validate using JSON (NOT pickle)
        message = validate_message(raw_data)

        task_type = message["task_type"]
        payload = message["payload"]
        metadata = message.get("metadata", {})

        job_id = metadata.get("job_id", "unknown")
        logger.info("Processing job_id=%s, task_type=%s", job_id, task_type)

        # Dispatch to the appropriate registered handler
        handler = ALLOWED_TASK_TYPES[task_type]
        result = handler(payload)

        logger.info(
            "Successfully processed job_id=%s, result_summary=%s",
            job_id,
            {k: type(v).__name__ for k, v in result.items()} if isinstance(result, dict) else type(result).__name__,
        )

        return result

    except json.JSONDecodeError as e:
        logger.error("Failed to decode JSON message: %s", e)
        raise
    except ValueError as e:
        logger.error("Validation error: %s", e)
        raise
    except Exception as e:
        logger.error("Unexpected error processing message: %s", e)
        raise


# --- Utility for publishing tasks (for use by producers) ---

def create_task_message(task_type, payload, job_id=None, priority=1):
    """
    Helper to create a properly formatted task message for publishing.

    Usage:
        from google.cloud import pubsub_v1
        publisher = pubsub_v1.PublisherClient()
        topic_path = publisher.topic_path(project_id, topic_id)

        message = create_task_message(
            task_type="data_transform",
            payload={"data": [1, 2, 3], "operation": "sum"},
            job_id="job-123"
        )
        publisher.publish(topic_path, message)
    """
    if task_type not in ALLOWED_TASK_TYPES:
        raise ValueError(f"Unknown task type: {task_type}")

    message = {
        "task_type": task_type,
        "payload": payload,
        "metadata": {
            "job_id": job_id or f"job-{datetime.utcnow().isoformat()}",
            "priority": priority,
            "created_at": datetime.utcnow().isoformat(),
        },
    }

    # Serialize safely as JSON - no pickle!
    return json.dumps(message).encode("utf-8")